import{_ as e,a as o,b as a}from"./chunks/File_preview.CG9FyhLS.js";import{_ as s,c as r,o as n,ah as i}from"./chunks/framework.RCw5T9E9.js";const b=JSON.parse('{"title":"Customize","description":"","frontmatter":{"title":"Customize"},"headers":[],"relativePath":"options/customize.md","filePath":"options/customize.md"}'),l={name:"options/customize.md"};function d(g,t,h,c,p,u){return n(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="customize" tabindex="-1">Customize <a class="header-anchor" href="#customize" aria-label="Permalink to &quot;Customize&quot;">​</a></h1><p><img src="'+e+'" alt="Персонализация"></p><p><strong>Options → General → Customize</strong> controls the main inspector look: theme, background media, and how it is displayed. You style the <strong>tool</strong>, not the site content.</p><hr><h2 id="extension-vs-standalone" tabindex="-1">Extension vs standalone <a class="header-anchor" href="#extension-vs-standalone" aria-label="Permalink to &quot;Extension vs standalone&quot;">​</a></h2><p>Fields (<strong>theme</strong>, <strong>file / URL</strong>, opacity, blur, noise, position, scale) match. What differs is <strong>where file bytes go</strong> and <strong>whether a total quota applies</strong>.</p><table tabindex="0"><thead><tr><th></th><th><strong>Extension (Chrome / Edge)</strong></th><th><strong>Standalone</strong></th></tr></thead><tbody><tr><td><strong>Where uploads live</strong></td><td>Media copies in extension <strong>IndexedDB</strong> (separate stores for wallpaper and saved files).</td><td>Media goes into the app’s <strong>unified local store</strong> (central quota).</td></tr><tr><td><strong>Size limit</strong></td><td>No app-enforced “N MB for media”; real cap is <strong>IndexedDB / storage quota</strong> for the extension profile.</td><td><strong>Hard 30 MB</strong> total for decorative media in standalone storage — saves are blocked if the new total would exceed (error like “Media limit exceeded”).</td></tr><tr><td><strong>Usage meter</strong></td><td>The <strong>X MB / 30 MB</strong> counter <strong>does not</strong> show in Customize.</td><td>Customize shows <strong>usage</strong> of the media store (<strong>MB of 30 MB</strong>) so you see remaining headroom.</td></tr></tbody></table><p><strong>URL backgrounds</strong> do not count like uploaded files in local quota, but for offline predictability local files within quota are often simpler (in standalone respect <strong>30 MB</strong> total).</p><hr><h2 id="theme" tabindex="-1">Theme <a class="header-anchor" href="#theme" aria-label="Permalink to &quot;Theme&quot;">​</a></h2><p><img src="'+o+'" alt="Персонализация: селекторы"></p><p><strong>Dark / Light</strong> toggles inspector color scheme.</p><hr><h2 id="background-image" tabindex="-1">Background (Image) <a class="header-anchor" href="#background-image" aria-label="Permalink to &quot;Background (Image)&quot;">​</a></h2><p><strong>Image</strong> sets the panel background. Sources — <strong>File</strong> and <strong>Link</strong>:</p><ul><li><strong>File</strong> — local asset via <strong>Browse</strong> or previously saved copies (extension: IndexedDB; standalone: unified 30 MB store — table above). Presets: <a href="/qa-tools/docs/options/settings_management.html">Settings management</a>.</li><li><strong>Link</strong> — URL to media.</li></ul><p>Supported: <strong>still images</strong>, animated <strong>GIF</strong>, <strong>MP4</strong> video backgrounds.</p><hr><h2 id="background-rendering" tabindex="-1">Background rendering <a class="header-anchor" href="#background-rendering" aria-label="Permalink to &quot;Background rendering&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Control</th><th>Role</th></tr></thead><tbody><tr><td><strong>Image Opacity</strong></td><td>Background layer transparency vs UI chrome.</td></tr><tr><td><strong>Blur</strong></td><td>Blur strength.</td></tr><tr><td><strong>Noise Intensity / Opacity</strong></td><td>Grain overlay strength/visibility.</td></tr><tr><td><strong>Position (X / Y)</strong></td><td>Pan the image.</td></tr><tr><td><strong>Scale</strong></td><td>Zoom <strong>100–200%</strong>.</td></tr></tbody></table><p>Combined, you can keep background subtle or decorative without hurting readability.</p><hr><h2 id="saved-files" tabindex="-1">Saved files <a class="header-anchor" href="#saved-files" aria-label="Permalink to &quot;Saved files&quot;">​</a></h2><p><img src="'+a+'" alt="Предпросмотр файла"></p><p>The <strong>Saved Files</strong> section on the <strong>General</strong> page keeps local media copies for reuse.</p><p>They are used in several places:</p><ul><li>picking a background file in <strong>Customize</strong>;</li><li><strong>File</strong> fields in <strong>Form-data</strong> at a <strong>Network</strong> breakpoint;</li><li>anywhere else the inspector needs to re-select a file you already saved.</li></ul><p><strong>Extension</strong> vs <strong>standalone</strong> storage rules match the table above: same idea, different backing store and total capacity.</p><h3 id="file-list" tabindex="-1">File list <a class="header-anchor" href="#file-list" aria-label="Permalink to &quot;File list&quot;">​</a></h3><p>The main control is a table of saved files.</p><p>Through it you can:</p><ul><li>browse saved entries;</li><li>delete files;</li><li>reuse them in supported editors.</li></ul><p>The same table lists <strong>Saved Files</strong> entries and <strong>Customize</strong> background media (<strong>wallpapers</strong>) together — one shared inspector media store (where it lives and any size cap still follow the <strong>Extension vs standalone</strong> table above).</p><h3 id="auto-saving-new-files" tabindex="-1">Auto-saving new files <a class="header-anchor" href="#auto-saving-new-files" aria-label="Permalink to &quot;Auto-saving new files&quot;">​</a></h3><p><strong>Auto-save new files selected via Browse</strong> controls whether new files are added to the list automatically.</p><p>When the option is on, a file is written to <strong>Saved Files</strong> when:</p><ul><li>it was chosen via <strong>Browse</strong>;</li><li>there is not already an entry with the same <strong>name + size</strong> pair.</li></ul><p>This applies, for example, when editing <strong>Form-data</strong> at a <strong>Network</strong> breakpoint.</p><h3 id="use-in-form-data" tabindex="-1">Use in Form-data <a class="header-anchor" href="#use-in-form-data" aria-label="Permalink to &quot;Use in Form-data&quot;">​</a></h3><p>When you pick a file from the list in the <strong>Form-data</strong> editor, the draft stores a service reference of the form <strong><code>__fileId:</code>…</strong>.</p><p>When changes are applied, the injected script uses that id to attach the real file bytes to the request.</p><p>Details: <a href="/qa-tools/docs/network/traffic.html">Traffic interception</a>.</p><hr><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="/qa-tools/docs/options/display_mode.html">Display modes</a></li><li><a href="/qa-tools/docs/options/settings_management.html">Settings management</a></li></ul>',45)])])}const k=s(l,[["render",d]]);export{b as __pageData,k as default};
